SELECT SUM(estimate) AS total_population
FROM demographic_data
WHERE dataset_name = 'ACS' AND year = 2022;

SELECT name
FROM geographic_areas
WHERE parent_geo_id IS NULL AND population > (SELECT AVG(population) FROM geographic_areas WHERE parent_geo_id IS NULL);

SELECT SUM(population) AS total_population
FROM geographic_areas
WHERE parent_geo_id = '1';

SELECT MIN(estimate) 
FROM demographic_data 
WHERE dataset_name = 'Census' AND category = 'population';

SELECT SUM(ga.population) AS total_population
FROM geographic_areas AS ga
WHERE ga.parent_geo_id = '1';

SELECT name
FROM geographic_areas
ORDER BY population DESC;

SELECT AVG(population) AS average_population
FROM geographic_areas
WHERE parent_geo_id = 'state_id';

SELECT name, population, area_sq_km
FROM geographic_areas
WHERE geo_id = '1';

SELECT dataset_name, AVG(estimate) AS avg_estimate
FROM demographic_data
GROUP BY dataset_name;
